    <div
      className="navbar-brand"
      onClick={() => navigate('/')}
      style={{ cursor: 'pointer' }}
    >
      JP-<span>Bridge</span>
    </div>

    {/* ACTIONS */}
    <div className="navbar-actions">

      {/* 🔔 Notifications */}
      <button className="icon-btn" onClick={handleNotif} title="Notifications">
        🔔
        {unread > 0 && (
          <span className="badge">{unread > 9 ? '9+' : unread}</span>
        )}
      </button>

      {/* 🌙 THEME TOGGLE */}
      <button
        className="icon-btn"
        onClick={toggleTheme}
        title="Toggle Theme"
      >
        {dark ? '🌙' : '☀️'}
      </button>

      {/* ⚙️ ADMIN */}
      {user?.isAdmin && (
        <button
          className="icon-btn"
          onClick={() => navigate('/admin')}
          title="Admin"
        >
          ⚙️
        </button>
      )}

      {/* 👤 PROFILE */}
      <button
        className="icon-btn"
        onClick={() => navigate('/profile')}
        style={{ padding: 0, overflow: 'hidden' }}
      >
        {user?.profilePhoto ? (
          <img
            src={user.profilePhoto}
            alt={user.name}
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        ) : (
          <span>{user?.name?.[0]?.toUpperCase()}</span>
        )}
      </button>

    </div>
  </div>
</nav>


);
};

export default Navbar;
